+        let dim = shape[axis];
+        if dim == 0 {
+            return Err(MAError::Msg(format!(
+                "flat index into zero-length axis {axis}"
+            )));
+        }
+        let coord = index % dim;
+        index /= dim;
+        path[axis] = i64::try_from(coord)
+            .map_err(|_| MAError::Msg("flat index coordinate overflow".to_string()))?;
+    }
+
+    Ok(path)
